const getPool = () => {
  if (pool) {
    return pool;
  }

  const rawConnection = process.env.DATABASE_URL;
  const connectionString = rawConnection ? rawConnection.replace(/^['"]|['"]$/g, "") : "";

  if (!connectionString) {
    throw new Error("DATABASE_URL is not configured in environment variables");
  }

  pool = new Pool({
    connectionString,
    ssl: { rejectUnauthorized: false },
  });

  return pool;
};

const initSchema = async () => {
  const db = getPool();
  await db.query(`
    CREATE TABLE IF NOT EXISTS users (
      id BIGSERIAL PRIMARY KEY,
      name VARCHAR(120) NOT NULL,
      email VARCHAR(255) NOT NULL UNIQUE,
      password_hash TEXT NOT NULL,
      role VARCHAR(20) NOT NULL CHECK (role IN ('viewer', 'analyst', 'admin')),
      status VARCHAR(20) NOT NULL CHECK (status IN ('active', 'inactive')),
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

    CREATE TABLE IF NOT EXISTS financial_records (
      id BIGSERIAL PRIMARY KEY,
      amount NUMERIC(14,2) NOT NULL CHECK (amount > 0),
      type VARCHAR(20) NOT NULL CHECK (type IN ('income', 'expense')),
      category VARCHAR(120) NOT NULL,
      record_date DATE NOT NULL,
      description TEXT,
      created_by BIGINT NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

    CREATE INDEX IF NOT EXISTS idx_financial_records_type ON financial_records(type);
    CREATE INDEX IF NOT EXISTS idx_financial_records_category ON financial_records(category);
    CREATE INDEX IF NOT EXISTS idx_financial_records_record_date ON financial_records(record_date);
    CREATE INDEX IF NOT EXISTS idx_financial_records_created_by ON financial_records(created_by);
  `);
};

const connectDB = async () => {
  const db = getPool();
  await db.query("SELECT 1");
  await initSchema();
};

const registerUser = async (req, res, next) => {
  try {
    const { name, email, password, role, status } = req.body;

    const normalizedEmail = email.toLowerCase();
    const existingUser = await query(`SELECT id FROM users WHERE email = $1`, [normalizedEmail]);
    if (existingUser.rowCount > 0) {
      return res.status(400).json({
        error: "BadRequest",
        code: 400,
        detail: "Email is already registered",
      });
    }

    const passwordHash = await bcrypt.hash(password, 10);
    const created = await query(
      `
        INSERT INTO users (name, email, password_hash, role, status)
        VALUES ($1, $2, $3, $4, $5)
        RETURNING id, name, email, role, status, created_at, updated_at
      `,
      [
        name,
        normalizedEmail,
        passwordHash,
        role || "viewer",
        status || "active",
      ]
    );

    const user = created.rows[0];

    return res.status(201).json({
      message: "User registered successfully",
      user: {
        id: Number(user.id),
        name: user.name,
        email: user.email,
        role: user.role,
        status: user.status,
        createdAt: user.created_at,
        updatedAt: user.updated_at,
      },
    });
  } catch (error) {
    return next(error);
  }
};

const loginUser = async (req, res, next) => {
  try {
    const { email, password } = req.body;
    const normalizedEmail = email.toLowerCase();
    const userResult = await query(
      `
        SELECT id, name, email, password_hash, role, status
        FROM users
        WHERE email = $1
      `,
      [normalizedEmail]
    );

    if (userResult.rowCount === 0) {
      return res.status(401).json({
        error: "Unauthorized",
        code: 401,
        detail: "Invalid credentials",
      });
    }

    const user = userResult.rows[0];
    const isPasswordValid = await bcrypt.compare(password, user.password_hash);
    if (!isPasswordValid) {
      return res.status(401).json({
        error: "Unauthorized",
        code: 401,
        detail: "Invalid credentials",
      });
    }

    if (user.status !== "active") {
      return res.status(403).json({
        error: "Forbidden",
        code: 403,
        detail: "Inactive users cannot login",
      });
    }

    const token = generateToken(Number(user.id));

    return res.status(200).json({
      message: "Login successful",
      token,
      user: {
        id: Number(user.id),
        name: user.name,
        email: user.email,
        role: user.role,
        status: user.status,
      },
    });
  } catch (error) {
    return next(error);
  }
};

const getSummary = async (req, res, next) => {
  try {
    const summaryResult = await query(`
      SELECT
        COALESCE(SUM(CASE WHEN type = 'income' THEN amount ELSE 0 END), 0)::FLOAT AS total_income,
        COALESCE(SUM(CASE WHEN type = 'expense' THEN amount ELSE 0 END), 0)::FLOAT AS total_expenses
      FROM financial_records
    `);

    const row = summaryResult.rows[0];
    const totalIncome = Number(row.total_income);
    const totalExpenses = Number(row.total_expenses);
    const netBalance = totalIncome - totalExpenses;

    return res.status(200).json({ totalIncome, totalExpenses, netBalance });
  } catch (error) {
    return next(error);
  }
};

const getCategoryBreakdown = async (req, res, next) => {
  try {
    const breakdownResult = await query(`
      SELECT
        category,
        COALESCE(SUM(CASE WHEN type = 'income' THEN amount ELSE 0 END), 0)::FLOAT AS income,
        COALESCE(SUM(CASE WHEN type = 'expense' THEN amount ELSE 0 END), 0)::FLOAT AS expense
      FROM financial_records
      GROUP BY category
      ORDER BY category ASC
    `);

    const categories = breakdownResult.rows.map((item) => {
      const income = Number(item.income);
      const expense = Number(item.expense);
      return {
        category: item.category,
        income,
        expense,
        total: income + expense,
      };
    });

    return res.status(200).json({ categories });
  } catch (error) {
    return next(error);
  }
};

const getRecentRecords = async (req, res, next) => {
  try {
    const recordsResult = await query(`
      SELECT
        fr.id,
        fr.amount,
        fr.type,
        fr.category,
        fr.record_date,
        fr.description,
        fr.created_at,
        fr.updated_at,
        u.id AS created_by_id,
        u.name AS created_by_name,
        u.email AS created_by_email,
        u.role AS created_by_role
      FROM financial_records fr
      INNER JOIN users u ON u.id = fr.created_by
      ORDER BY fr.record_date DESC, fr.created_at DESC
      LIMIT 5
    `);

    const records = recordsResult.rows.map((row) => ({
      id: Number(row.id),
      amount: Number(row.amount),
      type: row.type,
      category: row.category,
      date: row.record_date,
      description: row.description,
      createdBy: {
        id: Number(row.created_by_id),
        name: row.created_by_name,
        email: row.created_by_email,
        role: row.created_by_role,
      },
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    }));

    return res.status(200).json({ records });
  } catch (error) {
    return next(error);
  }
};

const getMonthlyTrends = async (req, res, next) => {
  try {
    const trendsResult = await query(`
      SELECT
        EXTRACT(YEAR FROM record_date)::INT AS year,
        EXTRACT(MONTH FROM record_date)::INT AS month,
        COALESCE(SUM(CASE WHEN type = 'income' THEN amount ELSE 0 END), 0)::FLOAT AS income,
        COALESCE(SUM(CASE WHEN type = 'expense' THEN amount ELSE 0 END), 0)::FLOAT AS expense
      FROM financial_records
      GROUP BY year, month
      ORDER BY year ASC, month ASC
    `);

    const monthly = trendsResult.rows.map((item) => {
      const income = Number(item.income);
      const expense = Number(item.expense);
      return {
        year: item.year,
        month: item.month,
        income,
        expense,
        net: income - expense,
      };
    });

    return res.status(200).json({ trends: monthly });
  } catch (error) {
    return next(error);
  }
};

