const getRecords = async (req, res, next) => {
  try {
    const { type, category, startDate, endDate, page = 1, limit = 10 } = req.query;

    const whereParts = [];
    const values = [];
    let index = 1;

    if (type) {
      whereParts.push(`fr.type = $${index++}`);
      values.push(type);
    }
    if (category) {
      whereParts.push(`fr.category = $${index++}`);
      values.push(category);
    }
    if (startDate) {
      whereParts.push(`fr.record_date >= $${index++}`);
      values.push(startDate);
    }
    if (endDate) {
      whereParts.push(`fr.record_date <= $${index++}`);
      values.push(endDate);
    }

    const parsedPage = Number(page);
    const parsedLimit = Number(limit);
    const skip = (parsedPage - 1) * parsedLimit;
    const whereClause = whereParts.length > 0 ? `WHERE ${whereParts.join(" AND ")}` : "";

    const countResult = await query(
      `
        SELECT COUNT(*)::INT AS total
        FROM financial_records fr
        ${whereClause}
      `,
      values
    );

    const recordsResult = await query(
      `
        SELECT
          fr.id,
          fr.amount,
          fr.type,
          fr.category,
          fr.record_date,
          fr.description,
          fr.created_at,
          fr.updated_at,
          u.id AS created_by_id,
          u.name AS created_by_name,
          u.email AS created_by_email,
          u.role AS created_by_role
        FROM financial_records fr
        INNER JOIN users u ON u.id = fr.created_by
        ${whereClause}
        ORDER BY fr.record_date DESC, fr.created_at DESC
        LIMIT $${index++} OFFSET $${index}
      `,
      [...values, parsedLimit, skip]
    );

    const total = countResult.rows[0].total;
    const records = recordsResult.rows.map(mapRecordRow);

    return res.status(200).json({
      total,
      page: parsedPage,
      pages: total === 0 ? 0 : Math.ceil(total / parsedLimit),
      limit: parsedLimit,
      records,
    });
  } catch (error) {
    return next(error);
  }
};

const getRecordById = async (req, res, next) => {
